// 获取所有输入数据
const allItems = $input.all();

// 假设所有的图片都在第一个输入 Item 中（通常 n8n 会把 binary 放在第一个 item 或均匀分布）
// 我们先提取出所有的 binary 数据
const allBinaries = {};
allItems.forEach(item => {
  if (item.binary) {
    Object.assign(allBinaries, item.binary);
  }
});

let results = [];

// 遍历输入，提取 descriptions 下的所有图
// 假设 descriptions 在第一个 Item 的 json 中
const descriptions = allItems[0].json.descriptions;

for (const key in descriptions) {
  results.push({
    json: {
      image_key: key,            // 对应 "1图", "2图" 等
      prompt: descriptions[key]  // 对应具体的描述文本
    },
    // 将之前收集到的所有二进制数据完整复制给每一个 item
    binary: { ...allBinaries } 
  });
}

return results;

// ================================================
// n8n Code 节点 - 提取描述和合并图像
// 支持原有全部格式 + 中文：第一张图 + 英文：First Image / Second Image...
// 新增：从 Edit Image 节点提取所有图片
// ================================================

let text = '';
const descriptions = {};
const images = {};
let index = 0;

// 中文数字映射
const cnNumMap = { '一':1, '二':2, '三':3, '四':4, '五':5, '六':6, '七':7, '八':8, '九':9, '十':10 };
// 英文顺序映射（新增！）
const enNumMap = {
  'first':1, 'second':2, 'third':3, 'fourth':4, 'fifth':5,
  'sixth':6, 'seventh':7, 'eighth':8, 'ninth':9, 'tenth':10
};

// 1. 提取所有输入项的文本和 binary
const allItems = $input.all();

for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];

  // 提取文本
  if (item.json?.output && typeof item.json.output === 'string') {
    text += item.json.output + '\n';
  }

  // 提取当前 item 的 binary
  if (item.binary) {
    for (const originalKey in item.binary) {
      if (Object.prototype.hasOwnProperty.call(item.binary, originalKey)) {
        const newKey = `${++index}图`;
        images[newKey] = {
          ...item.binary[originalKey],
          sourceNode: 'current_input',
          sourceField: originalKey,
          originalIndex: i
        };
      }
    }
  }
}

// 2. 清洗文本
text = text
  .replace(/^\s*<\|\s*begin_of_box\s*\|>\s*/i, '')
  .replace(/\s*<\|\s*end_of_box\s*\|>\s*$/i, '')
  .trim();

// 3. 解析描述 —— 优先尝试新的 JSON markdown 格式
let parsedFromJson = false;

const jsonBlockMatch = text.match(/```(?:json)?\s*(\[[\s\S]*?\])\s*```/);
if (jsonBlockMatch) {
  try {
    const jsonArray = JSON.parse(jsonBlockMatch[1]);
    if (Array.isArray(jsonArray) && jsonArray.length > 0) {
      for (const entry of jsonArray) {
        if (typeof entry !== 'string') continue;

        let num = null;

        // 原有阿拉伯数字规则
        const numMatch = entry.match(/第?\s*(\d+)\s*张?(?:图|图片)|图片(\d+)|(\d+)图|(?:image[_\s]?)(\d+)/i);
        if(numMatch){
          num = numMatch[1] || numMatch[2] || numMatch[3] || numMatch[4];
        }

        // 中文：第一张图
        const cnMatch = entry.match(/第([一二三四五六七八九十]+)张图/);
        if(cnMatch && cnNumMap[cnMatch[1]]){
          num = cnNumMap[cnMatch[1]];
        }

        // 新增：First Image / Second Image...
        const enMatch = entry.match(/(first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)\s*image/i);
        if (enMatch) {
          num = enNumMap[enMatch[1].toLowerCase()];
        }

        if (num) {
          const colonIdx = entry.indexOf('：');
          const colonIdx2 = entry.indexOf(':');
          const idx = colonIdx !== -1 ? colonIdx : colonIdx2;
          if (idx !== -1) {
            const value = entry.substring(idx + 1).trim();
            if (value) {
              descriptions[`${num}图`] = value;
              parsedFromJson = true;
            }
          }
        }
      }
    }
  } catch (e) {
    console.log('JSON 解析失败，降级使用正则匹配:', e.message);
  }
}

// 4. 用统一正则：原有全部 + 中文 + 英文
if (!parsedFromJson || Object.keys(descriptions).length === 0) {
  const imagePattern = /(?:第\s*(\d+)\s*张(?:图|图片)|第?\s*(\d+)\s*图|图片(\d+)|(?:image[_\s]?)(\d+)|(\d+)\s*image|第([一二三四五六七八九十])张图|(first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)\s*image)/gi;

  let match;
  const matches = [];

  while ((match = imagePattern.exec(text)) !== null) {
    let num = match[1] || match[2] || match[3] || match[4] || match[5];

    // 中文
    const cnChar = match[6];
    if(cnChar && cnNumMap[cnChar]) num = cnNumMap[cnChar];

    // 新增英文
    const enWord = match[7];
    if (enWord) num = enNumMap[enWord.toLowerCase()];

    if (num) {
      matches.push({ index: match.index, num: Number(num), length: match[0].length });
    }
  }

  // 根据位置切分描述文本
  for (let i = 0; i < matches.length; i++) {
    const current = matches[i];
    const next = matches[i + 1];
    const startIdx = current.index + current.length;
    const endIdx = next ? next.index : text.length;

    let descText = text.substring(startIdx, endIdx)
      .replace(/^[：:\s—\-–]+/, '')
      .replace(/\n+$/, '')
      .trim();

    if (descText && current.num) {
      descriptions[`${current.num}图`] = descText;
    }
  }

  // 兜底：旧格式
  if (Object.keys(descriptions).length === 0) {
    const pattern = /第\s*(\d+)\s*张图片([（(][^）)]+[）)])\s*[：:]\s*([\s\S]*?)(?=第\s*\d+\s*张图片|$)/g;
    while ((match = pattern.exec(text)) !== null) {
      const num = match[1];
      const size = match[2];
      let value = match[3].trim().replace(/\n+$/, '');
      if (value) {
        descriptions[`${num}图`] = `第 ${num} 张图片${size}：${value}`;
      }
    }
  }
}

// 5. 从 Edit Fields 节点提取 cpimage 开头的 binary
let editFieldsImageCount = 0;
