// ================================================
// 6. 【新增】从 Edit Image 节点提取 所有 图片 binary
// ================================================
let editImageImageCount = 0;
let editImageConnected = false;

try {
  let editImageNode;
  try { editImageNode = $('Edit Image5'); } catch(e) {}
  try { if (!editImageNode) editImageNode = $('Edit_Image'); } catch(e) {}
  try { if (!editImageNode) editImageNode = $('edit-image'); } catch(e) {}

  const editImageOutput = editImageNode ? editImageNode.all() : [];

  for (const item of editImageOutput) {
    if (!item?.binary) continue;
    for (const key in item.binary) {
      // 提取 Edit Image 输出的 所有图片（不限制名称）
      const newKey = `${++index}图`;
      images[newKey] = {
        ...item.binary[key],
        sourceNode: 'Edit Image',
        sourceField: key
      };
      editImageImageCount++;
    }
  }
  editImageConnected = editImageImageCount > 0;
} catch (err) {
  console.error("Edit Image node error:", err.message);
}

// 7. 输出（增加了 Edit Image 统计）
return [{
  json: {
    descriptions,
    images: Object.keys(images),
    imageCount: Object.keys(images).length,
    descriptionCount: Object.keys(descriptions).length,
    inputImageCount: index - editFieldsImageCount - editImageImageCount,
    editFieldsImageCount,
    editFieldsConnected,
    editImageImageCount,      // 新增
    editImageConnected,       // 新增
    matchedPairs: Object.keys(descriptions).filter(k => images[k]).length,
    parsedFromJson
  },
  binary: images
}];

