// 【辅助函数：文本防空与清洗】
function sanitizeString(str) {
    // 1. 处理 null, undefined, 空值，统一返回空字符串
    if (str === null || str === undefined || str === '') return '';

    // 2. 强制转为字符串
    let cleanStr = String(str);

    // 3. 去除可能导致 JSON 截断或 AI 理解错误的非法控制字符（保留 \n 换行符用于排版）
    cleanStr = cleanStr.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '');

    // 4. 将 Windows (\r\n) 和 Mac (\r) 换行符统一为 Unix (\n)，避免双重换行
    cleanStr = cleanStr.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

    return cleanStr;
}

// 【辅助函数：Base64 图片防空与清洗】
function cleanBase64(base64Str) {
    if (!base64Str) return null;
    let clean = String(base64Str).trim();
    // 1. 去除可能存在的 Data URI 前缀 (如 "data:image/png;base64,")
    if (clean.includes(',')) {
        clean = clean.split(',')[1];
    }
    // 2. 去除所有空白字符（换行、空格），防止破坏 JSON 结构
    clean = clean.replace(/\s+/g, '');
    return clean;
}

