const number = Number(productBody.number) || 6; // 确保是数字类型
const language = sanitizeString(productBody.language || '英文');
const ProductInformation = sanitizeString(productBody.ProductInformation);

// 图片数据防空：确保它真的是一个数组
const base64_cpimage = Array.isArray(topJson.base64_cpimage) ? topJson.base64_cpimage : [];

// 提取上游策划方案的 output 内容
const rawUpstreamOutput = topJson.output ? String(topJson.output) : '';
const upstreamOutput = sanitizeString(rawUpstreamOutput);

// ================================================
// 完整 Prompt 文本 (增强版)
