// ================================================
// 构建 parts 数组
// ================================================
const parts = [
  { text: promptText },
  { text: `\n\n=== 以下是用户提供的产品信息（非常重要） ===\n${ProductInformation}` }
];

// 将上游节点的 output 作为重要上下文注入（防空：只有当内容不为空时才注入）
if (upstreamOutput) {
  parts.push({
    text: `\n\n=== 上游策划方案（必须严格执行此方案中的文案和模块选择） ===\n${upstreamOutput}\n=== 方案结束 ===`
  });
}

// 【防线3：图片防空】
if (base64_cpimage.length > 0) {
  parts.push({ text: '\n\n产品参考图：' });
  for (const base64 of base64_cpimage) {
    const cleanData = cleanBase64(base64);
    // 只有当清洗后的 base64 存在，且长度大于 100（过滤掉无效的空值或极短字符串）时才推入数组
    if (cleanData && typeof cleanData === 'string' && cleanData.length > 100) {
      parts.push({
        inline_data: { mime_type: 'image/jpeg', data: cleanData }
      });
    }
  }
}

// ================================================
// 组装完整请求体 & 输出
// ================================================
const requestBody = {
  contents: [{ parts }]
};

// 全新输出对象，不修改原始数据
return [{
  json: {
    ...topJson,
    requestBody: requestBody,
    requestBodyJson: JSON.stringify(requestBody),
    // 调试信息：方便在 n8n 中排查数据是否被正确提取
    _debug: {
      extractedNumber: number,
      hasUpstreamOutput: !!upstreamOutput,
      upstreamOutputLength: upstreamOutput.length,
      validImageCount: parts.filter(p => p.inline_data).length
    }
  }
}];

// ================================================ 
// 获取 taskId，计算完整路径，按顺序命名图片 
// 统一 binary 键名为 data，重命名 fileName 为 img_1.png 格式 
// 同时创建日期+taskId的文件夹 
// ================================================ 

const fs = require('fs'); 
const path = require('path'); 

const allItems = $input.all(); 

// 尝试多种方式获取 taskId 
let taskId = ''; 

// 方式1：从当前节点的 json 中获取 
const firstItem = allItems[0] || {}; 
if (firstItem.json?.taskId) { 
  taskId = firstItem.json.taskId; 
} 

// 方式2：从"path"节点获取（生成ID的节点） 
if (!taskId) { 
  try { 
    const basePathItems = $('Start').first().json.path_allItems; 
    if (basePathItems && basePathItems.length > 0) { 
      taskId = basePathItems[0].json?.taskId || ''; 
    } 
  } catch (e) { 
    console.log('无法从 path 获取 taskId'); 
  } 
} 

// 方式3：从 Respond to Webhook2 节点获取 
if (!taskId) { 
  try { 
    const respondItems = $('Start').first().json.Respond_to_Webhook2_allItems; 
    if (respondItems && respondItems.length > 0) { 
      taskId = respondItems[0].json?.taskId || ''; 
    } 
  } catch (e) { 
    console.log('无法从 Respond to Webhook2 获取 taskId'); 
  } 
} 

// 如果还是没有，使用时间戳作为备用 
if (!taskId) { 
  console.log('警告: 未找到 taskId，使用时间戳作为备用'); 
  taskId = `task_${Date.now()}`; 
} 

console.log('获取到的 taskId:', taskId); 

// 生成日期文件夹路径 
const now = new Date(); 
const yyyy = String(now.getFullYear()); 
const mm = String(now.getMonth() + 1).padStart(2, '0'); 
const dd = String(now.getDate()).padStart(2, '0'); 

// 文件夹路径 = 基础路径/日期/taskId 
const basePath = '/home/node/.n8n/AI-WEB'; 
const folderPath = path.join(basePath, yyyy, mm, dd, taskId); 

// 创建文件夹（如果不存在） 
let created = false; 
if (!fs.existsSync(folderPath)) { 
  fs.mkdirSync(folderPath, { recursive: true }); 
  created = true; 
  console.log('创建文件夹:', folderPath); 
} 

// 按顺序为每个 item 分配图片编号（img_1, img_2, img_3...） 
return allItems.map((item, index) => { 
  // 修改命名方式：img_1, img_2, img_3... 
  const imageName = `img_${index + 1}`; 
  const fullImagePath = `${folderPath}/${imageName}.png`; 

  // 获取原始 binary 数据 
  const originalBinary = item.binary || {}; 

  // 修改 binary：将所有键名统一为 "data"，fileName 改为 img_X.png 格式 
  const modifiedBinary = {}; 

  // 取第一个 binary 数据的属性作为模板 
  const firstKey = Object.keys(originalBinary)[0]; 
  const templateData = firstKey ? originalBinary[firstKey] : {}; 

  // 获取原始扩展名 
  const extension = (templateData.fileName || 'image.png').split('.').pop() || 'png'; 
  // 新文件名：img_1.png, img_2.png... 
  const newFileName = `${imageName}.${extension}`; 

  // 统一键名为 "data" 
  modifiedBinary['data'] = { 
    ...templateData, 
    fileName: newFileName 
  }; 

  console.log(`生成文件: ${newFileName}`); 

  return { 
    json: { 
      ...item.json, 
      taskId: taskId, 
      basePath: basePath, 
      imageName: imageName, 
      fullImagePath: fullImagePath, 
      // 传递给 Read/Write Files from Disk 
      savePath: fullImagePath, 
      // 用于创建文件夹 
      folderPath: folderPath, 
      created: created, 
      year: yyyy, 
      month: mm, 
      day: dd 
    }, 
    binary: modifiedBinary 
  }; 
});

// 获取所有输入项
const items = $input.all();

// 收集所有图片路径
const imagePaths = [];

// 提取 taskId
let taskId = null;

for (const item of items) {
    const json = item.json;

    // 【原有功能 1】提取 taskId
    if (json.taskId && !taskId) {
        taskId = json.taskId;
    }

    // 【原有功能 2】提取图片路径（从 /2026 开始）
    if (json.savePath) {
        const pathParts = json.savePath.split('/');
        // 兼容年份变化，查找 "2026" 或根据实际逻辑调整
        const yearIndex = pathParts.indexOf('2026');

        if (yearIndex !== -1) {
            const relativePath = '/' + pathParts.slice(yearIndex).join('/');
            imagePaths.push(relativePath);
        }
    }
}

// 【原有功能 3】直接输出带双引号的字符串格式
const imagePathsWithQuotes = imagePaths.map(path => `"${path}"`).join(',');

// ==========================================
// 【修复核心】构建输出数据
// ==========================================
// 获取上游传下来的所有原始数据（包含 workflowStartTime 以及其他所有业务字段）
const originalJson = items[0]?.json || {};

return [{
    json: {
        // 第一步：把上游的所有原始数据原封不动地继承下来（保留原有功能的关键）
        ...originalJson,

        // 第二步：输出当前节点处理后的业务字段
        taskId: taskId,
        imageCount: imagePaths.length,
        imagePathsComma: imagePathsWithQuotes,
        imagePaths: imagePaths,
        paths: imagePaths

        // 注意：这里已经移除了 generate_spend 和 startTime 相关的计算逻辑
    }
}];
